// ================================================================
// AGENT AI TARGETUP — GEMINI 1.5 FLASH (100% GRATUIT)
// aistudio.google.com → Get API Key → coller ci-dessous
// Limites gratuites : 15 req/min · 1500 req/jour
// Pour 50 emails/jour : largement suffisant
// ================================================================

const prenom = $input.item.json['Prenom'] || 'Cher(e) professionnel(le)';
const nom    = $input.item.json['Nom']    || '';
const email  = $input.item.json['Email'];
const row    = $input.item.json['row_number'];

// ⚙️ REMPLACER ICI PAR VOTRE CLÉ GEMINI
// Obtenir gratuitement sur : https://aistudio.google.com/app/apikey
const GEMINI_API_KEY = 'REMPLACER_PAR_VOTRE_CLE_GEMINI';

// ── Prompt complet envoyé à Gemini ──
// Gemini n'a pas de system prompt séparé comme Claude
// On intègre le rôle directement dans le prompt
const PROMPT = `Tu es l'Agent Commercial IA de TargetUp Group.

TargetUp Group est un groupe international de conseil stratégique, formation professionnelle et investissement basé à Rabat (Maroc) et Cardiff (Royaume-Uni).
Accréditations : ISO 9001 · ISO 21001 · ISO 37301 · AIAE USA · EOQM UK · UNGM Nations Unies · AMDIE.

Tes règles absolues :
- Chaque email est UNIQUE : jamais le même texte deux fois
- Tu commences TOUJOURS l'email par «Bonjour [Prénom],» sur sa propre ligne en gras, jamais autrement
- Tu ouvres ensuite avec une accroche personnalisée et percutante, jamais générique
- Tu sélectionnes 3 à 4 services TargetUp selon une logique de valeur ajoutée perçue
- Tu intègres des chiffres concrets pour crédibiliser
- Tu termines par un CTA précis : rendez-vous de 20 minutes
- Tu génères le HTML complet avec design dark mode rouge/noir/blanc
- Tu réponds UNIQUEMENT en JSON valide, rien d'autre

Génère un email de prospection B2B pour :
Prénom : ${prenom}
Nom : ${nom}

Services TargetUp disponibles (choisis 3-4) :
• Certifications ISO 9001 / 14001 / 45001 / 37301 — audit réussi en 3 à 6 mois garanti
• Formations certifiantes financées jusqu'à 100% — Lean Six Sigma, Lead Auditor PECB, DBA, MSc Management — via CSF / MOUWAKABA / OFPPT
• Transformation Digitale — ERP CRM Odoo, automatisation, +35% efficacité, ROI moyen 18 mois
• Programme Export Afrique Francophone — 10 marchés, accès BAD / AFD / Banque Mondiale, accréditation UNGM ONU
• Financement & Investissement — Maroc PME, INTELAKA, capital-risque 4 à 50 M MAD
• Lean Six Sigma & Excellence Opérationnelle — +20 à 50% efficacité documentés

Chiffres clés à utiliser : +1220 missions réussies · 100% financement possible · 3-6 mois certification · 10 marchés africains

Spécifications HTML (styles 100% inline, 600px max, compatible email) :
- Fond principal #111111, sections #1a1a1a / #1e1e1e
- Accent rouge #E01B1B : header, bouton CTA, titres services, bordures
- Texte principal #FFFFFF, secondaire #cccccc, labels #888888
- Header : symbole ◎ rouge + texte TARGET blanc UP rouge en gras + sous-titre CONSULTING espacé gris
- Barre KPI : 3 chiffres clés en rouge sur fond sombre
- Services listés avec ✅ et titres en rouge #E01B1B
- Bloc urgence : fond #1a1a1a, bordure gauche rouge 3px
- Bouton CTA : fond #E01B1B, texte blanc, border-radius 4px, padding 14px 32px
- Bloc pièce jointe PDF obligatoire : afficher un encadré visuel avec fond #1e1e1e, bordure #E01B1B, une icône PDF rouge (div 40x48px fond #E01B1B texte blanc «PDF»), le nom du fichier «TargetUp_Group_Brochure_2026.pdf» en blanc et la description «Brochure commerciale · Services · Références · Financements» en gris
- Signature : +212 684 48 17 30 · +212 684 77 88 54 · sales@targetupconsulting.com · targetupconsulting.com · 17 Rue Jbel Moussa Rabat 10090 Maroc · Cardiff CF14 8LH UK
- Footer : ISO 9001 · ISO 21001 · AIAE (USA) · EOQM (UK) · UNGM Nations Unies

Réponds UNIQUEMENT avec ce JSON (aucun texte avant ou après) :
{"subject":"...","html":"..."}`;

// ── Appel Gemini avec retry x3 ──
let result = null;
let lastError = '';

for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    const res = await $http.request({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${GEMINI_API_KEY}`,
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({
        contents: [{
          parts: [{ text: PROMPT }]
        }],
        generationConfig: {
          temperature: 0.9,
          maxOutputTokens: 4096,
          responseMimeType: 'application/json'
        }
      }),
      returnFullResponse: true
    });

    const body = typeof res.body === 'string' ? JSON.parse(res.body) : res.body;

    // Extraire le texte de la réponse Gemini
    const raw = body.candidates[0].content.parts[0].text.trim().replace(/```json|```/gi, '').trim();
    result = JSON.parse(raw);

    if (!result.subject || !result.html) throw new Error('subject ou html manquant');
    break;

  } catch (e) {
    lastError = e.message;
    if (attempt < 3) await new Promise(r => setTimeout(r, 4000));
  }
}

if (!result) throw new Error(`Agent Gemini échoué après 3 tentatives : ${lastError}`);

// ── Téléchargement PDF brochure TargetUp depuis Google Drive ──
let pdfBinary = null;
try {
  const pdfRes = await $http.request({
    method: 'GET',
    url: 'https://docs.google.com/presentation/d/1IgvCTyXVzE5LlP2HWss9l1uPyKVWJU6A/export/pdf',
    returnFullResponse: true,
    encoding: null
  });
  pdfBinary = {
    data: Buffer.from(pdfRes.body).toString('base64'),
    mimeType: 'application/pdf',
    fileName: 'TargetUp_Group_Brochure_2026.pdf'
  };
} catch (e) {
  // PDF indisponible : email envoyé sans pièce jointe, pas bloquant
}

// ── Retour final : email + PDF dans le même item ──
return [{
  json: {
    toEmail:   email,
    prenom:    prenom,
    nom:       nom,
    row:       row,
    subject:   result.subject,
    emailHtml: result.html,
    hasPdf:    pdfBinary !== null
  },
  binary: pdfBinary ? { brochure: pdfBinary } : {}
}];
